<template><div class="page-container"><FilterBar @search="onSearch" @reset="onReset"><a-input v-model:value="f.orderNo" placeholder="订单号" allow-clear style="width:180px"/><a-select v-model:value="f.status" placeholder="状态" allow-clear style="width:110px"><a-select-option value="pending">待支付</a-select-option><a-select-option value="success">成功</a-select-option><a-select-option value="failed">失败</a-select-option><a-select-option value="cancelled">已取消</a-select-option></a-select></FilterBar><div class="page-card"><DataTable :columns="cols" :data-source="list" :loading="ld" :total="t" v-model:page="p" v-model:page-size="ps"><template #amount="{r}">{{(+r.amount).toFixed(2)}}</template><template #status="{r}"><StatusTag :status="r.status" type="payment"/></template><template #a="{r}"><a-space><a>详情</a></a-space></template></DataTable></div></div></template>
<script setup lang="ts">import {ref,reactive} from 'vue';import {topupApi} from '@/api/topup';import FilterBar from '@/components/common/FilterBar.vue';import DataTable from '@/components/common/DataTable.vue';import StatusTag from '@/components/common/StatusTag.vue'
const ld=ref(false),list=ref<any[]>([]),t=ref(0),p=ref(1),ps=ref(20);const f=reactive({orderNo:'',status:undefined as string|undefined})
const cols=[{title:'订单号',dataIndex:'orderNo',width:180},{title:'用户',dataIndex:'userName',width:120},{title:'金额',dataIndex:'amount',width:80,slot:'amount'},{title:'支付渠道',dataIndex:'payChannel',width:100},{title:'状态',dataIndex:'status',width:90,slot:'status'},{title:'支付时间',dataIndex:'payTime',width:160},{title:'创建时间',dataIndex:'createdAt',width:160},{title:'操作',dataIndex:'action',width:80,slot:'a'}]
async function ft(){ld.value=true;try{const r=await topupApi.getOrderList({page:p.value,pageSize:ps.value,...f});list.value=r.data.data?.list||r.data?.list||[];t.value=r.data.data?.total||r.data?.total||0}catch{}finally{ld.value=false}}
function onSearch(){p.value=1;ft()};function onReset(){f.orderNo='';f.status=undefined;onSearch()}
ft();
</script>
